fn main() {
    let small: i8 = 100;
    let normal: i32 = 1_000_000;
    let big: i64 = 9_000_000_000;
    println!("{} {} {}", small, normal, big);
}

fn main() {
    let t = true;
    let f = false;
    println!("{} {}", t, f);
    println!("{}", 5 > 3);
    println!("{}", 5 == 5);
    println!("{}", !true);
}

fn main() {
    let letter = 'A';
    let digit = '9';
    let crab = '\u{1F980}';
    println!("{} {} {}", letter, digit, crab);
    println!("{}", 'z' as u32);
}

fn main() {
    let x: i32 = 42;
    let y = x as f64;
    let z = 3.99_f64 as i32;
    println!("{} {} {}", x, y, z);
}

fn main() {
    let x: i32 = i32::MAX;
    println!("max i32: {}", x);
    println!("checked add: {:?}", x.checked_add(1));
    println!("saturating: {}", x.saturating_add(1));
}

fn main() {
    let n: i32 = -42;
    println!("{}", n.abs());
    println!("{}", 2_i32.pow(8));
    println!("{:.2}", 2.0_f64.sqrt());
    println!("{}", i32::MIN);
}
